// Create Google Drive subfolder structure for the topic
// In production, this would use Google Drive API to create folders
// For now, generate placeholder folder IDs and structure
const topic = $input.first().json[0];
const topicId = topic.id;
const topicNumber = topic.topic_number;
const title = topic.seo_title || topic.original_title || `Topic ${topicNumber}`;

// Subfolder structure to be created on Google Drive
const subfolders = {
  audio: null,
  images: null,
  video_clips: null,
  captions: null,
  final: null
};

return [{
  json: {
    topic_id: topicId,
    project_id: topic.project_id,
    topic_number: topicNumber,
    title: title,
    drive_folder_id: topic.drive_folder_id,
    drive_subfolder_ids: subfolders
  }
}];

// Batch trigger: set first topic to 'audio', rest to 'queued'
const topicIds = $input.first().json.body.topic_ids || [];
if (!topicIds.length) {
  return [{ json: { error: 'No topic_ids provided', topic_ids: [] } }];
}

// First topic starts immediately, rest queued
return [{
  json: {
    first_topic_id: topicIds[0],
    queued_topic_ids: topicIds.slice(1),
    all_topic_ids: topicIds
  }
}];

// Determine resume stage from last production_log entry
const logEntries = $input.first().json;
const topicId = $('Webhook Resume').item.json.body.topic_id;

let resumeStage = 'audio'; // default
let webhookPath = 'production/tts';

if (Array.isArray(logEntries) && logEntries.length > 0) {
  const lastStage = logEntries[0].stage;
  switch (lastStage) {
    case 'audio':
      resumeStage = 'audio';
      webhookPath = 'production/tts';
      break;
    case 'images':
      resumeStage = 'images';
      webhookPath = 'production/images';
      break;
    case 'i2v':
      resumeStage = 'images';
      webhookPath = 'production/i2v';
      break;
    case 't2v':
      resumeStage = 'images';
      webhookPath = 'production/t2v';
      break;
    case 'assembly':
      resumeStage = 'assembling';
      webhookPath = 'production/assemble';
      break;
    default:
      resumeStage = 'audio';
      webhookPath = 'production/tts';
  }
}

return [{
  json: {
    topic_id: topicId,
    resume_stage: resumeStage,
    webhook_path: webhookPath
  }
}];

// Determine which stage failed and reset it
const scenes = $input.first().json;
if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{ json: { error: 'Scene not found' } }];
}
const scene = scenes[0];
const resetFields = {};
let failedStage = '';

if (scene.audio_status === 'failed') {
  resetFields.audio_status = 'pending';
  failedStage = 'tts';
} else if (scene.image_status === 'failed') {
  resetFields.image_status = 'pending';
  failedStage = scene.visual_type === 'static_image' ? 'images' : 'images';
} else if (scene.video_status === 'failed') {
  resetFields.video_status = 'pending';
  failedStage = scene.visual_type === 'i2v' ? 'i2v' : 't2v';
} else if (scene.clip_status === 'failed') {
  resetFields.clip_status = 'pending';
  failedStage = 'assembly';
}

return [{
  json: {
    scene_id: scene.id,
    topic_id: scene.topic_id,
    scene_number: scene.scene_number,
    visual_type: scene.visual_type,
    failed_stage: failedStage,
    reset_fields: resetFields
  }
}];

// Reset all failed statuses to pending
const scenes = $input.first().json;
if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{ json: { count: 0, scene_ids: [] } }];
}

const sceneIds = scenes.map(s => s.id);
return [{ json: { count: scenes.length, scene_ids: sceneIds, topic_id: $('Webhook Retry All Failed').item.json.body.topic_id } }];
